			flagGroupsDependent: []string{"a b", "a c"},
			args:                []string{"--a=foo"},
			expectErr:           `if flag "a" is set, the following flags must also be set: [b c]`,
		},
		{
			desc:                "Validation of dependent groups occurs on groups in sorted order",
			flagGroupsDependent: []string{"a c", "a b"},
			args:                []string{"--a=foo"},
			expectErr:           `if flag "a" is set, the following flags must also be set: [b c]`,
		},
		{
			desc:                "Persistent flags can be dependents",
			flagGroupsDependent: []string{"a e"},
			args:                []string{"--a=foo"},
			expectErr:           `if flag "a" is set, the following flags must also be set: [e]`,
		},
