			flagGroupsDependent: []string{"a e", "e f"},
			args:                []string{"--a=foo", "--e=foo"},
			expectErr:           `if flag "e" is set, the following flags must also be set: [f]`,
		},
		{
			desc:                "Dependent groups pass with persistent flags",
			flagGroupsDependent: []string{"a e", "e f"},
			args:                []string{"--a=foo", "--e=foo", "--f=foo"},
		},
		{
			desc:                     "Subcmds can use dependent groups using inherited flags",
			subCmdFlagGroupsDep:      []string{"e subonly"},
			args:                     []string{"subcmd", "--e=foo", "--subonly=foo"},
		},
		{
			desc:                     "Subcmds can use dependent groups and fail",
			subCmdFlagGroupsDep:      []string{"e subonly"},
			args:                     []string{"subcmd", "--e=foo"},
			expectErr:                `if flag "e" is set, the following flags must also be set: [subonly]`,
		},
