func TestValidateFlagDependentGroups(t *testing.T) {
	getCmd := func() *Command {
		c := &Command{
			Use: "testcmd",
			Run: func(cmd *Command, args []string) {
			},
		}
		// Define lots of flags to utilize for testing.
		for _, v := range []string{"a", "b", "c", "d"} {
			c.Flags().String(v, "", "")
		}
		for _, v := range []string{"e", "f", "g"} {
			c.PersistentFlags().String(v, "", "")
		}
		subC := &Command{
			Use: "subcmd",
			Run: func(cmd *Command, args []string) {
			},
		}
		subC.Flags().String("subonly", "", "")
		c.AddCommand(subC)
		return c
	}

	testcases := []struct {
		desc                 string
		flagGroupsDependent  []string
		subCmdFlagGroupsDep  []string
		args                 []string
		expectErr            string
	}{
		{
			desc: "No flags no problem",
		},
		{
			desc:                "No flags no problem even with dependent groups",
			flagGroupsDependent: []string{"a b"},
		},
		{
			desc:                "Dependent flag group not satisfied - primary set but dependent missing",
			flagGroupsDependent: []string{"a b"},
			args:                []string{"--a=foo"},
			expectErr:           `if flag "a" is set, the following flags must also be set: [b]`,
		},
		{
			desc:                "Dependent flag group satisfied - both primary and dependent set",
			flagGroupsDependent: []string{"a b"},
			args:                []string{"--a=foo", "--b=foo"},
		},
		{
			desc:                "Dependent flag group satisfied - only dependent set (no primary)",
			flagGroupsDependent: []string{"a b"},
			args:                []string{"--b=foo"},
		},
		{
			desc:                "Multiple dependent groups not satisfied returns first error",
			flagGroupsDependent: []string{"a b", "a c"},
			args:                []string{"--a=foo"},
			expectErr:           `if flag "a" is set, the following flags must also be set: [b c]`,
		},
		{
			desc:                "Validation of dependent groups occurs on groups in sorted order",
			flagGroupsDependent: []string{"a c", "a b"},
			args:                []string{"--a=foo"},
			expectErr:           `if flag "a" is set, the following flags must also be set: [b c]`,
		},
		{
			desc:                "Persistent flags can be dependents",
			flagGroupsDependent: []string{"a e"},
			args:                []string{"--a=foo"},
			expectErr:           `if flag "a" is set, the following flags must also be set: [e]`,
		},
		{
			desc:                "Persistent flags can be primary",
			flagGroupsDependent: []string{"e f"},
			args:                []string{"--e=foo"},
			expectErr:           `if flag "e" is set, the following flags must also be set: [f]`,
		},
		{
			desc:                "Persistent flags can be both primary and dependent",
			flagGroupsDependent: []string{"a e", "e f"},
			args:                []string{"--a=foo", "--e=foo"},
			expectErr:           `if flag "e" is set, the following flags must also be set: [f]`,
		},
		{
			desc:                "Dependent groups pass with persistent flags",
			flagGroupsDependent: []string{"a e", "e f"},
			args:                []string{"--a=foo", "--e=foo", "--f=foo"},
		},
		{
			desc:                     "Subcmds can use dependent groups using inherited flags",
			subCmdFlagGroupsDep:      []string{"e subonly"},
			args:                     []string{"subcmd", "--e=foo", "--subonly=foo"},
		},
		{
			desc:                     "Subcmds can use dependent groups and fail",
			subCmdFlagGroupsDep:      []string{"e subonly"},
			args:                     []string{"subcmd", "--e=foo"},
			expectErr:                `if flag "e" is set, the following flags must also be set: [subonly]`,
		},
		{
			desc:                     "Flag groups not applied if not found on invoked command",
			subCmdFlagGroupsDep:      []string{"e subonly"},
			args:                     []string{"--e=foo"},
		},
	}
	for _, tc := range testcases {
		t.Run(tc.desc, func(t *testing.T) {
			c := getCmd()
			sub := c.Commands()[0]
			for _, flagGroup := range tc.flagGroupsDependent {
				parts := strings.Split(flagGroup, " ")
				c.MarkFlagsDependent(parts[0], parts[1])
			}
			for _, flagGroup := range tc.subCmdFlagGroupsDep {
				parts := strings.Split(flagGroup, " ")
				sub.MarkFlagsDependent(parts[0], parts[1])
			}
			c.SetArgs(tc.args)
			err := c.Execute()
			switch {
			case err == nil && len(tc.expectErr) > 0:
				t.Errorf("Expected error %q but got nil", tc.expectErr)
			case err != nil && err.Error() != tc.expectErr:
				t.Errorf("Expected error %q but got %q", tc.expectErr, err)
			}
		})
	}
}

